class InstationaryModel(pymor.basic.InstationaryModel):
    """Extend pyMOR's `InstationaryModel` to include a `data` attribute for storing, e.g., the model's grid."""
    def __init__(
        self,
        T,
        initial_data,
        operator,
        rhs,
        mass=None,
        time_stepper=None,
        num_values=None,
        output_functional=None,
        products=None,
        error_estimator=None,
        visualizer=None,
        name=None,
        data=None
    ):
        self.data = data
        if products:
            for k, v in products.items():
                setattr(self, k, lambda u, mu=None, v=v: v.apply(u, mu))
        super().__init__(
        T,
        initial_data,
        operator,
        rhs,
        mass=mass,
        time_stepper=time_stepper,
        num_values=num_values,
        output_functional=output_functional,
        products=products,
        error_estimator=error_estimator,
        visualizer=visualizer,
        name=name,
    )

