# %% ../../nbs/api/pymor/models.ipynb
def fourier_space(n): 
    return XarrayVectorSpace({'Fourier coefficient': sym_range(n)})

# %% ../../nbs/api/pymor/models.ipynb
def to_sympy(functional):
    if isinstance(functional, Number):
        return functional
    if isinstance(functional, ProductParameterFunctional):
        return math.prod(to_sympy(factor) for factor in functional.factors)
    if isinstance(functional, ExpressionParameterFunctional): 
        out = functional.expression
    else:
        out = functional
    return parse_expr(out)

# %% ../../nbs/api/pymor/models.ipynb
def fourier_series(expr, n, t:str='t', nu:str='nu'):
    t = sy.Symbol(t)
    return sy.fourier_series(
        expr.subs(nu, 1), 
        (t, -sy.pi, sy.pi)
    ).truncate(
        n=n+1
    ).rewrite(
        sy.exp
    ).expand()

# %% ../../nbs/api/pymor/models.ipynb
def fourier_series_coefficients(series:Expr, n:int, t:str='t'):
    """Returns the positive and negative Fourier series coefficients up to and including order `n`.
    """
    t = sy.Symbol(t)
    return array([
        series.coeff(sy.exp(sy.I*t) if k != 0 else t, n=k) 
        for k in range(-n, n+1)
    ])

# %% ../../nbs/api/pymor/models.ipynb
def fourier_expansion_operator(coefficient, n_operator, n_vector, mu:dict=None, t:str='t', nu:str='nu') -> np.ndarray:
    """Coefficients of complex Fourier series of expr in variable `t` at frequency `nu`.

    Assumes that either the coefficients are numerical, or there is only the zero-order coefficient. Could be useful to generalize.
    """
    space = fourier_space(n_vector)
    if isinstance(coefficient, Number):
        return IdentityOperator(space) * coefficient        
    expr = to_sympy(coefficient)
    if mu is not None: expr = expr.subs(mu)
    if not expr.has(sy.Symbol(t)): 
        return IdentityOperator(space) * coefficient
    series = fourier_series(expr, n_operator, t=t, nu=nu)
    coeffs = fourier_series_coefficients(series, n_operator, t=t).astype(complex)
    return XarrayMatrixOperator(
        sparse_toeplitz(np.pad(coeffs, n_vector + 1)),
        source=space,
        range=space
    )

